def tokenize(expression: str) -> list[Token]:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        char = expression[i]

        if char.isspace():
            i += 1
            continue

        if char.isdigit():
            start = i
            while i < n and (expression[i].isdigit() or expression[i] == "."):
                i += 1
            num_str = expression[start:i]
            tokens.append(Token(TokenType.NUMBER, float(num_str)))
            continue

        if char == "+":
            tokens.append(Token(TokenType.PLUS, "+"))
        elif char == "-":
            tokens.append(Token(TokenType.MINUS, "-"))
        elif char == "*":
            tokens.append(Token(TokenType.MULTIPLY, "*"))
        elif char == "/":
            tokens.append(Token(TokenType.DIVIDE, "/"))
        elif char == "(":
            tokens.append(Token(TokenType.LPAREN, "("))
        elif char == ")":
            tokens.append(Token(TokenType.RPAREN, ")"))
        else:
            raise ParserError(f"Invalid character: {char}")

        i += 1

    tokens.append(Token(TokenType.EOF, None))
    return tokens


def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    tokens = tokenize(expression)
    pos = 0

    def current_token():
        return tokens[pos]

    def advance():
        nonlocal pos
        pos += 1

    def parse_expression() -> ASTNode:
        return parse_additive()

    def parse_additive() -> ASTNode:
        node = parse_multiplicative()

        while current_token().type in (TokenType.PLUS, TokenType.MINUS):
            op = current_token().type
            advance()
            right = parse_multiplicative()
            node = ASTNode(NodeType.BINOP, op=op, left=node, right=right)

        return node

    def parse_multiplicative() -> ASTNode:
        node = parse_unary()

        while current_token().type in (TokenType.MULTIPLY, TokenType.DIVIDE):
            op = current_token().type
            advance()
            right = parse_unary()
            node = ASTNode(NodeType.BINOP, op=op, left=node, right=right)

        return node

    def parse_unary() -> ASTNode:
        if current_token().type == TokenType.MINUS:
            advance()
            operand = parse_unary()
            return ASTNode(NodeType.UNARY, op=TokenType.MINUS, operand=operand)
        return parse_primary()

    def parse_primary() -> ASTNode:
        token = current_token()

        if token.type == TokenType.NUMBER:
            advance()
            return ASTNode(NodeType.NUMBER, value=token.value)
        elif token.type == TokenType.LPAREN:
            advance()
            expr = parse_expression()
            if current_token().type != TokenType.RPAREN:
                raise ParserError("Unmatched parenthesis")
            advance()
            return expr
        else:
            raise ParserError(f"Unexpected token: {token.type}")

    result = parse_expression()

    if current_token().type != TokenType.EOF:
        raise ParserError(f"Unexpected token: {current_token().type}")

    return result


def evaluate(node: ASTNode) -> float:
    if node.type == NodeType.NUMBER:
        return node.value

    elif node.type == NodeType.BINOP:
        left_val = evaluate(node.left) if node.left is not None else 0.0
        right_val = evaluate(node.right) if node.right is not None else 0.0

        if node.op == TokenType.PLUS:
            return left_val + right_val
        elif node.op == TokenType.MINUS:
            return left_val - right_val
        elif node.op == TokenType.MULTIPLY:
            return left_val * right_val
        elif node.op == TokenType.DIVIDE:
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val

    elif node.type == NodeType.UNARY:
        operand_val = evaluate(node.operand) if node.operand is not None else 0.0
        if node.op == TokenType.MINUS:
            return -operand_val

    raise ParserError(f"Unknown node type: {node.type}")
